html_content = '{% load static %}\n<!DOCTYPE html>\n<html lang="es">\n<head>\n    <meta charset="utf-8" />\n    <meta content="width=device-width, initial-scale=1.0" name="viewport" />\n    <title>ReservaEDU - Plataforma Global de Gestión de Espacios</title>\n    <meta name="description" content="Plataforma global para la gestión y reserva de espacios corporativos y académicos.">\n    <link href="https://fonts.googleapis.com" rel="preconnect" />\n    <link crossorigin="" href="https://fonts.gstatic.com" rel="preconnect" />\n    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Manrope:wght@600;700;800&display=swap" rel="stylesheet" />\n    <link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&display=swap" rel="stylesheet" />\n    <script src="https://cdn.tailwindcss.com?plugins=forms"></script>\n    <script>\n        tailwind.config = {\n            theme: {\n                extend: {\n                    colors: {\n                        primary: "#00236f", "primary-dark": "#001a54",\n                        secondary: "#d32f2f", "secondary-dark": "#b71c1c",\n                        surface: "#f8fafc", "on-surface": "#0f172a"\n                    },\n                    fontFamily: { display: ["Manrope", "sans-serif"], body: ["Inter", "sans-serif"] }\n                }\n            }\n        }\n    </script>\n    <style>\n        body { font-family: \'Inter\', sans-serif; background-color: #f8fafc; }\n        h1, h2, h3, .font-display { font-family: \'Manrope\', sans-serif; }\n        .material-symbols-outlined { font-variation-settings: \'FILL\' 0, \'wght\' 400, \'GRAD\' 0, \'opsz\' 24; }\n        .glass-panel { background: rgba(255, 255, 255, 0.9); backdrop-filter: blur(16px); border: 1px solid rgba(255, 255, 255, 0.2); }\n        \n        /* AI Chat Styles */\n        .ai-dark { background: #1e1e24; color: #f1f5f9; border: 1px solid rgba(255, 255, 255, 0.05); }\n        .ai-bubble { background: #2d2d35; border-radius: 1.5rem; border-top-left-radius: 0.2rem; }\n        .user-bubble { background: #00236f; border-radius: 1.5rem; border-top-right-radius: 0.2rem; color: white; }\n        .ai-gradient { background: linear-gradient(135deg, #00236f, #d32f2f); }\n        .ai-glow { box-shadow: 0 0 20px rgba(211, 47, 47, 0.3); }\n        \n        /* Animations */\n        .fade-in { animation: fadeIn 0.4s ease-out forwards; }\n        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }\n        \n        .thinking-glow { position: relative; overflow: hidden; height: 2px; }\n        .thinking-glow::after { content: \'\'; position: absolute; inset: 0; background: linear-gradient(90deg, transparent, #d32f2f, #00236f, transparent); animation: sweep 2s infinite; }\n        @keyframes sweep { from { transform: translateX(-100%); } to { transform: translateX(100%); } }\n        \n        /* Custom Scrollbar */\n        ::-webkit-scrollbar { width: 6px; }\n        ::-webkit-scrollbar-track { background: transparent; }\n        ::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }\n    </style>\n</head>\n<body class="text-on-surface antialiased">\n    {% if user.is_authenticated or user_simulated %}\n    <div class="flex h-screen overflow-hidden">\n        \n        <!-- Sidebar -->\n        <aside class="w-64 bg-white border-r border-slate-200 flex flex-col shadow-sm relative z-20">\n            <div class="p-6">\n                <div class="flex items-center gap-3 mb-1">\n                    <div class="w-8 h-8 rounded-lg bg-secondary flex items-center justify-center shadow-lg shadow-secondary/30">\n                        <span class="material-symbols-outlined text-white text-sm">public</span>\n                    </div>\n                    <h2 class="text-xl font-black text-primary tracking-tight font-display">RESERVAEDU</h2>\n                </div>\n                <p class="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-11">Global Network</p>\n            </div>\n            \n            <nav class="flex-1 px-4 space-y-2 overflow-y-auto mt-4">\n                <a id="nav-spaces" onclick="switchView(\'spaces\')" class="flex items-center gap-3 px-4 py-3 bg-primary text-white rounded-xl shadow-md cursor-pointer transition-all hover:bg-primary-dark">\n                    <span class="material-symbols-outlined">grid_view</span>\n                    <span class="font-bold text-sm">Espacios</span>\n                </a>\n                <a id="nav-horarios" onclick="switchView(\'horarios\')" class="flex items-center gap-3 px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-primary rounded-xl cursor-pointer transition-all">\n                    <span class="material-symbols-outlined">calendar_month</span>\n                    <span class="font-bold text-sm">Horarios</span>\n                </a>\n                <a id="nav-reservations" onclick="switchView(\'reservations\')" class="flex items-center gap-3 px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-primary rounded-xl cursor-pointer transition-all">\n                    <span class="material-symbols-outlined">book_online</span>\n                    <span class="font-bold text-sm">Mis Reservas</span>\n                </a>\n            </nav>\n            \n            <div class="p-4 border-t border-slate-200">\n                <form action="{% url \'logout\' %}" method="post">\n                    {% csrf_token %}\n                    <button type="submit" class="w-full flex items-center gap-3 px-4 py-3 text-secondary hover:bg-red-50 rounded-xl transition-all text-left font-bold text-sm">\n                        <span class="material-symbols-outlined">logout</span>\n                        <span>Cerrar sesión</span>\n                    </button>\n                </form>\n            </div>\n        </aside>\n\n        <!-- Main Content -->\n        <main class="flex-1 flex flex-col relative overflow-hidden bg-slate-50">\n            <!-- Topbar -->\n            <header class="h-16 glass-panel border-b border-slate-200 px-8 flex justify-between items-center z-10 sticky top-0">\n                <div></div>\n                <div class="flex items-center gap-4">\n                    <button onclick="toggleAIChat()" class="px-5 py-2 rounded-full bg-secondary text-white font-bold text-xs uppercase tracking-widest shadow-lg shadow-secondary/20 hover:bg-secondary-dark transition-all flex items-center gap-2">\n                        <span class="material-symbols-outlined text-sm">auto_awesome</span> RESERVA AI\n                    </button>\n                    <div class="h-6 w-px bg-slate-300 mx-2"></div>\n                    <span class="text-sm font-bold text-primary">{{ user.username }}{{ sim_username }}</span>\n                    <img class="w-8 h-8 rounded-full border-2 border-white shadow-sm" src="https://api.dicebear.com/7.x/initials/svg?seed={{ user.username }}{{ sim_username }}&backgroundColor=00236f" />\n                </div>\n            </header>\n\n            <!-- Scrollable View Area -->\n            <div class="flex-1 overflow-y-auto p-8 relative">\n                \n                <!-- VIEW: SPACES -->\n                <div id="view-spaces" class="max-w-7xl mx-auto fade-in">\n                    <div class="mb-10 flex flex-wrap items-center justify-between gap-4">\n                        <div>\n                            <h1 class="text-3xl font-black text-primary font-display mb-2">Directorio de Espacios</h1>\n                            <p class="text-slate-500 text-sm">Explora y reserva recursos en la red global.</p>\n                        </div>\n                        <div class="flex bg-white rounded-xl shadow-sm border border-slate-200 p-1">\n                            <button onclick="filterSpaces(\'Espacios\')" class="px-6 py-2 rounded-lg bg-primary text-white font-bold text-sm filter-btn shadow-sm" data-category="Espacios">Catálogo</button>\n                            <button onclick="filterSpaces(\'Horarios\')" class="px-6 py-2 rounded-lg text-slate-500 font-bold text-sm filter-btn hover:text-primary transition-colors" data-category="Horarios">Horarios Guardados</button>\n                        </div>\n                        <button id="btn-delete-all" onclick="deleteAllSchedules()" class="hidden px-5 py-2 rounded-lg bg-red-50 text-secondary font-bold text-sm border border-red-100 hover:bg-red-100 transition-all items-center gap-2">\n                            <span class="material-symbols-outlined text-sm">delete_sweep</span> Borrar Todos\n                        </button>\n                    </div>\n\n                    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6" id="spaces-grid">\n                        {% for espacio in espacios %}\n                        <article data-category="{{ espacio.categoria }}" class="space-card bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-100 hover:shadow-xl hover:-translate-y-1 transition-all duration-300 flex flex-col group">\n                            <div class="relative h-48 overflow-hidden bg-slate-200">\n                                <img src="https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=800" class="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />\n                                <div class="absolute top-3 left-3"><span class="bg-white/95 text-secondary text-[10px] font-black uppercase px-3 py-1 rounded-full shadow-sm">{{ espacio.categoria }}</span></div>\n                            </div>\n                            <div class="p-6 flex-1 flex flex-col">\n                                <h3 class="text-xl font-bold text-primary mb-2 leading-tight">{{ espacio.nombre }}</h3>\n                                <p class="text-slate-500 text-xs mb-6 flex-1 line-clamp-3">{{ espacio.descripcion }}</p>\n                                <button onclick="openSpaceDetail(\'{{ espacio.nombre }}\', \'{{ espacio.categoria }}\', \'{{ espacio.capacidad }}\', \'{{ espacio.descripcion }}\', \'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=800\')" class="w-full bg-primary/5 hover:bg-primary text-primary hover:text-white py-2.5 rounded-xl font-bold text-sm transition-colors border border-primary/10">Ver Disponibilidad</button>\n                            </div>\n                        </article>\n                        {% endfor %}\n                    </div>\n                </div>\n\n                <!-- VIEW: RESERVATIONS -->\n                <div id="view-reservations" class="max-w-5xl mx-auto hidden fade-in">\n                    <div class="mb-10 flex items-center justify-between">\n                        <div>\n                            <h1 class="text-3xl font-black text-primary font-display mb-2">Mis Reservas</h1>\n                            <p class="text-slate-500 text-sm">Gestiona tus confirmaciones activas.</p>\n                        </div>\n                    </div>\n                    <div id="reservation-list" class="space-y-4">\n                        <div id="no-reservations" class="bg-white rounded-2xl p-16 text-center border border-slate-200 shadow-sm">\n                            <div class="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">\n                                <span class="material-symbols-outlined text-4xl text-slate-300">event_busy</span>\n                            </div>\n                            <h3 class="text-lg font-bold text-primary mb-2">Sin reservas activas</h3>\n                            <p class="text-slate-500 text-sm max-w-sm mx-auto">Cuando confirmes un espacio, aparecerá aquí junto con su estado de aprobación.</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </main>\n    </div>\n\n    <!-- Modals -->\n    <div id="space-modal" class="fixed inset-0 z-[100] hidden items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">\n        <div class="bg-white max-w-3xl w-full rounded-3xl overflow-hidden shadow-2xl relative scale-95 opacity-0 transition-all duration-300 flex flex-col md:flex-row" id="modal-content">\n            <button onclick="closeModal()" class="absolute top-4 right-4 z-10 w-8 h-8 rounded-full bg-black/10 text-white flex items-center justify-center hover:bg-black/20 transition-colors"><span class="material-symbols-outlined text-sm">close</span></button>\n            \n            <div class="w-full md:w-5/12 h-64 md:h-auto relative bg-slate-200">\n                <img id="modal-image" class="w-full h-full object-cover">\n                <div class="absolute inset-0 bg-gradient-to-t from-primary-dark/90 to-transparent flex flex-col justify-end p-6">\n                    <span id="modal-category" class="text-secondary font-bold text-[10px] uppercase tracking-widest mb-1"></span>\n                    <h2 id="modal-title" class="text-white text-2xl font-black font-display leading-tight"></h2>\n                </div>\n            </div>\n            \n            <div class="w-full md:w-7/12 p-8 flex flex-col bg-white">\n                <p id="modal-description" class="text-sm text-slate-600 mb-6 leading-relaxed"></p>\n                \n                <div class="space-y-5 mb-8">\n                    <div class="grid grid-cols-2 gap-4">\n                        <div>\n                            <label class="text-[10px] font-bold text-slate-400 uppercase mb-1.5 block">Fecha</label>\n                            <input id="res-date" type="date" class="w-full bg-slate-50 border border-slate-200 p-2.5 rounded-lg text-sm focus:ring-2 focus:ring-primary outline-none">\n                        </div>\n                        <div>\n                            <label class="text-[10px] font-bold text-slate-400 uppercase mb-1.5 block">Hora</label>\n                            <input id="res-time" type="time" class="w-full bg-slate-50 border border-slate-200 p-2.5 rounded-lg text-sm focus:ring-2 focus:ring-primary outline-none">\n                        </div>\n                    </div>\n                    <div>\n                        <label class="text-[10px] font-bold text-slate-400 uppercase mb-1.5 block">Notificar Asistencia a</label>\n                        <select id="res-notify" class="w-full bg-slate-50 border border-slate-200 p-2.5 rounded-lg text-sm focus:ring-2 focus:ring-primary outline-none">\n                            <option value="Ninguno">No notificar</option>\n                            <option value="Administración">Administración Global</option>\n                            <option value="Soporte IT">Soporte Técnico IT</option>\n                        </select>\n                    </div>\n                </div>\n\n                <div class="mt-auto flex items-center justify-between">\n                    <span class="text-xs font-bold text-slate-500 flex items-center gap-1.5"><span class="material-symbols-outlined text-[16px] text-secondary">group</span> Capacidad: <span id="modal-capacity" class="text-primary"></span> pax</span>\n                    <button onclick="confirmReservation()" class="bg-primary hover:bg-primary-dark text-white px-8 py-3 rounded-xl font-bold text-sm shadow-lg shadow-primary/20 transition-all">\n                        Confirmar Reserva\n                    </button>\n                </div>\n            </div>\n        </div>\n    </div>\n\n    <!-- AI Chat (RESERVA AI) -->\n    <div id="ai-chat" class="fixed bottom-6 right-6 z-[110] hidden w-[400px] shadow-2xl transition-all translate-y-10 opacity-0">\n        <div class="ai-dark rounded-3xl overflow-hidden flex flex-col h-[600px] border border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">\n            <div class="px-5 py-4 flex justify-between items-center border-b border-white/5 bg-white/5">\n                <div class="flex items-center gap-3">\n                    <div class="w-8 h-8 rounded-full ai-gradient flex items-center justify-center text-white ai-glow"><span class="material-symbols-outlined text-[16px]">auto_awesome</span></div>\n                    <div>\n                        <h4 class="text-sm font-black text-white font-display">RESERVA AI</h4>\n                        <p class="text-[9px] text-secondary font-bold uppercase tracking-widest">Asistente Global</p>\n                    </div>\n                </div>\n                <button onclick="toggleAIChat()" class="text-white/40 hover:text-white transition-colors"><span class="material-symbols-outlined text-[20px]">close</span></button>\n            </div>\n            \n            <div id="ai-messages" class="flex-1 overflow-y-auto p-5 space-y-5 text-sm">\n                <!-- Welcome Message -->\n                <div class="flex gap-3">\n                    <div class="w-8 h-8 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-secondary shrink-0"><span class="material-symbols-outlined text-[16px]">smart_toy</span></div>\n                    <div class="ai-bubble p-4 max-w-[85%] text-slate-200">\n                        ¡Hola! Soy RESERVA AI. Estoy conectado a la red global de espacios. ¿Te ayudo a generar un horario, encontrar un espacio específico o investigar algo en la red?\n                    </div>\n                </div>\n            </div>\n\n            <div id="search-indicator" class="hidden px-5 py-2 bg-white/5 flex items-center gap-3">\n                <div class="w-2 h-2 bg-secondary rounded-full animate-pulse"></div>\n                <span id="search-text" class="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Procesando consulta...</span>\n            </div>\n            <div id="ai-progress" class="hidden thinking-glow"></div>\n\n            <div class="p-4 bg-black/20 border-t border-white/5">\n                <div class="flex items-end gap-2 bg-white/5 rounded-2xl p-1 border border-white/10 focus-within:border-secondary/50 transition-colors">\n                    <textarea id="ai-input" \n                        class="flex-1 bg-transparent border-none px-3 py-2 text-sm text-white focus:ring-0 resize-none max-h-32 placeholder-white/30" \n                        placeholder="Escribe tu consulta aquí..." \n                        rows="1"\n                        oninput="this.style.height = \'\'; this.style.height = Math.min(this.scrollHeight, 120) + \'px\'"\n                        onkeydown="if(event.key === \'Enter\' && !event.shiftKey) { event.preventDefault(); sendMessage(); }"></textarea>\n                    <button onclick="sendMessage()" class="w-10 h-10 mb-0.5 rounded-xl flex items-center justify-center text-white bg-secondary hover:bg-secondary-dark transition-all shrink-0 shadow-md">\n                        <span class="material-symbols-outlined text-[18px]">send</span>\n                    </button>\n                </div>\n            </div>\n        </div>\n    </div>\n\n    <!-- Scripts -->\n    <script>\n        function switchView(v) {\n            document.getElementById(\'view-spaces\').classList.add(\'hidden\'); \n            document.getElementById(\'view-reservations\').classList.add(\'hidden\');\n            \n            document.querySelectorAll(\'aside nav a\').forEach(el => {\n                el.className = \'flex items-center gap-3 px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-primary rounded-xl cursor-pointer transition-all\';\n            });\n\n            if(v===\'spaces\' || v===\'horarios\') {\n                document.getElementById(\'view-spaces\').classList.remove(\'hidden\');\n                let target = v===\'spaces\' ? \'nav-spaces\' : \'nav-horarios\';\n                document.getElementById(target).className = \'flex items-center gap-3 px-4 py-3 bg-primary text-white rounded-xl shadow-md cursor-pointer transition-all hover:bg-primary-dark\';\n                filterSpaces(v===\'spaces\' ? \'Espacios\' : \'Horarios\');\n            } else {\n                document.getElementById(\'view-reservations\').classList.remove(\'hidden\');\n                document.getElementById(\'nav-reservations\').className = \'flex items-center gap-3 px-4 py-3 bg-primary text-white rounded-xl shadow-md cursor-pointer transition-all hover:bg-primary-dark\';\n                loadReservations();\n            }\n        }\n\n        function filterSpaces(cat) {\n            const delBtn = document.getElementById(\'btn-delete-all\');\n            delBtn.classList.toggle(\'hidden\', cat !== \'Horarios\');\n\n            document.querySelectorAll(\'.filter-btn\').forEach(b => {\n                if(b.dataset.category===cat) { b.className = \'px-6 py-2 rounded-lg bg-primary text-white font-bold text-sm filter-btn shadow-sm\'; }\n                else { b.className = \'px-6 py-2 rounded-lg text-slate-500 font-bold text-sm filter-btn hover:text-primary transition-colors\'; }\n            });\n            \n            document.querySelectorAll(\'.space-card\').forEach(c => {\n                const itemCat = c.dataset.category;\n                const isHorario = itemCat === \'Horarios\';\n                if(cat === \'Espacios\') c.style.display = isHorario ? \'none\' : \'flex\';\n                else if(cat === \'Horarios\') c.style.display = isHorario ? \'flex\' : \'none\';\n                else c.style.display = itemCat === cat ? \'flex\' : \'none\';\n            });\n        }\n\n        function openSpaceDetail(n, c, ca, d, img) {\n            document.getElementById(\'modal-title\').innerText=n;\n            document.getElementById(\'modal-category\').innerText=c;\n            document.getElementById(\'modal-capacity\').innerText=ca;\n            document.getElementById(\'modal-description\').innerText=d;\n            document.getElementById(\'modal-image\').src=img;\n            document.getElementById(\'res-date\').value=\'\';\n            document.getElementById(\'res-time\').value=\'\';\n            \n            const m=document.getElementById(\'space-modal\'); const mc=document.getElementById(\'modal-content\');\n            m.classList.replace(\'hidden\',\'flex\'); setTimeout(()=>{ mc.classList.replace(\'scale-95\',\'scale-100\'); mc.classList.replace(\'opacity-0\',\'opacity-100\'); },10);\n        }\n\n        function closeModal() {\n            const m=document.getElementById(\'space-modal\'); const mc=document.getElementById(\'modal-content\');\n            mc.classList.replace(\'scale-100\',\'scale-95\'); mc.classList.replace(\'opacity-100\',\'opacity-0\');\n            setTimeout(()=> m.classList.replace(\'flex\',\'hidden\'), 300);\n        }\n\n        function confirmReservation() {\n            const d=document.getElementById(\'res-date\').value, t=document.getElementById(\'res-time\').value, n=document.getElementById(\'res-notify\').value;\n            const title=document.getElementById(\'modal-title\').innerText;\n            if(!d || !t) { showToast("Seleccione fecha y hora", "error"); return; }\n            \n            const res = JSON.parse(localStorage.getItem(\'reservas_global\') || \'[]\');\n            res.push({ id:Date.now(), title, d, t, n, status:\'Aprobación Pendiente\' });\n            localStorage.setItem(\'reservas_global\', JSON.stringify(res));\n            \n            showToast(`Reserva en \'${title}\' confirmada`, "success");\n            closeModal();\n        }\n\n        function loadReservations() {\n            const l=document.getElementById(\'reservation-list\'), nr=document.getElementById(\'no-reservations\');\n            const data=JSON.parse(localStorage.getItem(\'reservas_global\') || \'[]\');\n            l.innerHTML = \'\';\n            if(data.length===0) { l.appendChild(nr); nr.classList.remove(\'hidden\'); }\n            else {\n                nr.classList.add(\'hidden\');\n                data.forEach(r => {\n                    l.innerHTML += `\n                        <div class="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row items-center justify-between gap-4 fade-in">\n                            <div class="flex items-center gap-5 w-full md:w-auto">\n                                <div class="w-12 h-12 bg-primary/10 rounded-xl flex items-center justify-center text-primary"><span class="material-symbols-outlined">event_available</span></div>\n                                <div><h4 class="font-bold text-primary font-display">${r.title}</h4><p class="text-xs text-slate-500 mt-1">${r.d} • ${r.t}</p></div>\n                            </div>\n                            <div class="flex items-center gap-4 w-full md:w-auto justify-between md:justify-end">\n                                <p class="text-[10px] font-bold text-slate-400 uppercase tracking-widest hidden lg:block">Aviso: ${r.n}</p>\n                                <span class="bg-yellow-50 text-yellow-700 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-yellow-200">${r.status}</span>\n                            </div>\n                        </div>\n                    `;\n                });\n            }\n        }\n\n        function showToast(m,t) {\n            const x=document.createElement(\'div\'), c={success:\'bg-primary\',error:\'bg-secondary\'};\n            x.className=`${c[t]} text-white px-6 py-4 rounded-xl shadow-2xl fixed bottom-8 left-1/2 -translate-x-1/2 z-[300] fade-in font-bold text-sm flex items-center gap-3`;\n            x.innerHTML=`<span class="material-symbols-outlined">${t===\'success\'?\'check_circle\':\'error\'}</span> ${m}`;\n            document.body.appendChild(x);\n            setTimeout(()=>{x.style.opacity=\'0\';x.style.transition=\'opacity 0.5s\';setTimeout(()=>x.remove(),500)},3500);\n        }\n\n        /* --- Schedules Logic --- */\n        function saveSchedule(name, html, sync = true) {\n            const container = document.getElementById(\'spaces-grid\');\n            const cardId = "sch-" + Date.now();\n            const card = document.createElement(\'article\');\n            card.id = cardId;\n            card.dataset.category = "Horarios";\n            card.className = "space-card bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-200 flex flex-col";\n            card.innerHTML = `\n                <div class="p-4 bg-primary text-white flex justify-between items-center border-b border-primary-dark">\n                    <div><h3 class="font-black text-sm uppercase tracking-wider font-display">${name}</h3><span class="text-[9px] text-primary-200 bg-white/10 px-2 py-0.5 rounded-sm">Generado por AI</span></div>\n                    <button onclick="deleteSchedule(\'${cardId}\', \'${name}\')" class="text-white/50 hover:text-secondary transition-colors"><span class="material-symbols-outlined text-[18px]">delete</span></button>\n                </div>\n                <div class="p-3 flex-1 overflow-auto bg-slate-50 text-slate-800 text-xs">\n                    ${html.replace(/text-white\\/[0-9]+/g, \'text-slate-600\').replace(/text-white/g, \'text-slate-800\').replace(/bg-white\\/5/g, \'bg-slate-200\').replace(/divide-white\\/5/g, \'divide-slate-200\')}\n                </div>\n            `;\n            container.insertBefore(card, container.firstChild);\n            \n            if(sync) {\n                const s = JSON.parse(localStorage.getItem(\'horarios_global\') || \'[]\');\n                s.push({ id: cardId, name, html });\n                localStorage.setItem(\'horarios_global\', JSON.stringify(s));\n            }\n        }\n        function deleteSchedule(id, name) {\n            if(!confirm(`¿Eliminar horario: ${name}?`)) return;\n            document.getElementById(id).remove();\n            let s = JSON.parse(localStorage.getItem(\'horarios_global\') || \'[]\');\n            localStorage.setItem(\'horarios_global\', JSON.stringify(s.filter(x => x.id !== id)));\n            showToast("Horario eliminado", "success");\n        }\n        function deleteAllSchedules() {\n            if(!confirm("¿Eliminar TODOS los horarios guardados?")) return;\n            document.querySelectorAll(\'.space-card[data-category="Horarios"]\').forEach(c => c.remove());\n            localStorage.removeItem(\'horarios_global\');\n            showToast("Horarios eliminados", "success");\n        }\n        window.addEventListener(\'DOMContentLoaded\', () => {\n            const s = JSON.parse(localStorage.getItem(\'horarios_global\') || \'[]\');\n            s.forEach(i => saveSchedule(i.name, i.html, false));\n            filterSpaces(\'Espacios\');\n        });\n\n        /* --- AI Chat Logic --- */\n        function toggleAIChat() {\n            const c=document.getElementById(\'ai-chat\');\n            if(c.classList.contains(\'hidden\')) { c.classList.remove(\'hidden\'); setTimeout(()=>{ c.classList.replace(\'translate-y-10\',\'translate-y-0\'); c.classList.replace(\'opacity-0\',\'opacity-100\'); },10); }\n            else { c.classList.replace(\'translate-y-0\',\'translate-y-10\'); c.classList.replace(\'opacity-100\',\'opacity-0\'); setTimeout(()=>c.classList.add(\'hidden\'),300); }\n        }\n        async function typeWriter(el, text) {\n            el.innerHTML = text; // Simplified for speed/performance\n            document.getElementById(\'ai-messages\').scrollTop = 9999;\n        }\n        async function sendMessage(providedText = null) {\n            const i=document.getElementById(\'ai-input\'), m=document.getElementById(\'ai-messages\'); \n            const p=document.getElementById(\'ai-progress\'), st=document.getElementById(\'search-indicator\'), sl=document.getElementById(\'search-text\');\n            \n            const textRaw = providedText || i.value;\n            if(!textRaw.trim()) return;\n            const text = textRaw.toLowerCase().trim(); \n            if(!providedText) { i.value=\'\'; i.style.height = \'\'; }\n            \n            m.innerHTML += `<div class="flex justify-end gap-3 fade-in"><div class="user-bubble p-3 max-w-[85%] text-sm shadow-sm">${textRaw}</div></div>`;\n            m.scrollTop = m.scrollHeight;\n            \n            st.classList.remove(\'hidden\'); p.classList.remove(\'hidden\');\n            sl.innerText = "Consultando inteligencia global...";\n            \n            let responseText = "", extraHtml = "", suggestions = [];\n\n            try {\n                if(text.includes("asignar a")) {\n                    const lastMsg = m.lastElementChild.previousElementSibling;\n                    const table = lastMsg.querySelector(\'table\');\n                    if(table) {\n                        const groupName = text.replace("asignar a ", "").toUpperCase();\n                        saveSchedule(groupName, table.outerHTML);\n                        p.classList.add(\'hidden\'); st.classList.add(\'hidden\');\n                        showToast(`Horario asignado a ${groupName}`, "success");\n                        filterSpaces(\'Horarios\');\n                        document.getElementById(\'nav-horarios\').click();\n                        return;\n                    }\n                }\n\n                const response = await fetch(\'/investigar-ia/\', {\n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\', \'X-CSRFToken\': \'{{ csrf_token }}\' },\n                    body: JSON.stringify({ query: textRaw })\n                });\n                const data = await response.json();\n                \n                responseText = data.respuesta;\n                suggestions = data.sugerencias || [];\n                if(data.extra_table) extraHtml = data.extra_table;\n\n            } catch (err) {\n                responseText = "Hubo un error de conexión con la red global. Por favor, reintenta.";\n            }\n\n            p.classList.add(\'hidden\'); st.classList.add(\'hidden\');\n            const msgId = "msg-" + Date.now();\n            \n            let html = `<div class="flex gap-3 fade-in"><div class="w-8 h-8 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-secondary shrink-0"><span class="material-symbols-outlined text-[16px]">smart_toy</span></div><div class="ai-bubble p-4 max-w-[90%] text-slate-200 shadow-sm"><div id="${msgId}" class="leading-relaxed"></div><div class="mt-2 text-white/80">${extraHtml}</div>`;\n            if(suggestions.length > 0) {\n                html += `<div class="mt-3 flex flex-wrap gap-1.5">${suggestions.map(s => `<button onclick="sendMessage(\'${s.replace(/\'/g, "\\\'")}\')" class="bg-white/10 hover:bg-secondary text-white px-2.5 py-1 rounded-md text-[10px] font-bold transition-colors">${s}</button>`).join(\'\')}</div>`;\n            }\n            html += `</div></div>`;\n            m.innerHTML += html;\n            \n            await typeWriter(document.getElementById(msgId), responseText);\n        }\n    </script>\n    {% else %}\n    <!-- Landing Page (Unauthenticated) -->\n    <div class="min-h-screen bg-slate-50 flex flex-col">\n        <header class="h-20 glass-panel border-b border-slate-200 px-8 lg:px-16 flex justify-between items-center fixed w-full top-0 z-50">\n            <div class="flex items-center gap-3">\n                <div class="w-10 h-10 rounded-xl bg-primary flex items-center justify-center shadow-lg shadow-primary/20">\n                    <span class="material-symbols-outlined text-white">public</span>\n                </div>\n                <h1 class="text-2xl font-black text-primary font-display tracking-tight">RESERVAEDU</h1>\n            </div>\n            <div class="flex items-center gap-4">\n                <a href="{% url \'login\' %}" class="text-sm font-bold text-slate-600 hover:text-primary transition-colors hidden sm:block">Iniciar Sesión</a>\n                <a href="{% url \'registro\' %}" class="px-6 py-2.5 rounded-full bg-primary hover:bg-primary-dark text-white font-bold text-sm shadow-md transition-all">Regístrate</a>\n            </div>\n        </header>\n        \n        <main class="flex-1 flex flex-col items-center justify-center text-center px-4 pt-32 pb-20 relative">\n            <!-- decorative background -->\n            <div class="absolute inset-0 overflow-hidden pointer-events-none">\n                <div class="absolute -top-40 -right-40 w-96 h-96 bg-primary/5 rounded-full blur-3xl"></div>\n                <div class="absolute bottom-10 -left-20 w-80 h-80 bg-secondary/5 rounded-full blur-3xl"></div>\n            </div>\n            \n            <div class="relative z-10 max-w-4xl mx-auto">\n                <span class="inline-block px-4 py-1.5 rounded-full bg-secondary/10 text-secondary text-xs font-black uppercase tracking-widest mb-6">Plataforma Global</span>\n                <h2 class="text-5xl lg:text-7xl font-black text-slate-900 font-display leading-[1.1] mb-6">\n                    Gestiona tus espacios con <span class="text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary">Inteligencia Artificial</span>\n                </h2>\n                <p class="text-lg text-slate-500 max-w-2xl mx-auto mb-10">\n                    Descubre, coordina y reserva salas, auditorios y recursos físicos a nivel global. Optimiza tu tiempo con nuestro asistente RESERVA AI.\n                </p>\n                <div class="flex flex-col sm:flex-row items-center justify-center gap-4">\n                    <button onclick="window.location.href=\'?user=Admin_Global\'" class="px-8 py-4 rounded-xl bg-primary hover:bg-primary-dark text-white font-bold text-sm shadow-xl shadow-primary/20 transition-all flex items-center gap-2">\n                        <span class="material-symbols-outlined">rocket_launch</span> Explorar Demo Global\n                    </button>\n                    <a href="{% url \'login\' %}" class="px-8 py-4 rounded-xl bg-white hover:bg-slate-50 text-slate-700 font-bold text-sm shadow-sm border border-slate-200 transition-all">\n                        Acceso Corporativo\n                    </a>\n                </div>\n            </div>\n        </main>\n    </div>\n    {% endif %}\n</body>\n</html>\n'
